import React, { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import "./Register.css";

export default function Register() {
  const navigate = useNavigate();
  const [role, setRole] = useState("");

  function handleRegister(e) {
    e.preventDefault();
    const name = e.target.name.value.trim();
    const email = e.target.email.value.trim();
    const pass = e.target.pass.value;
    const cpass = e.target.cpass.value;

    const roll = e.target.roll ? e.target.roll.value.trim() : ""; // Only for students

    if (pass !== cpass) {
      alert("Passwords do not match!");
      return;
    }

    localStorage.setItem("userName", name);
    localStorage.setItem("email", email);
    localStorage.setItem("password", pass);
    localStorage.setItem("role", role);
    localStorage.setItem("rollNumber", roll);

    alert(`Registered successfully as ${role}!`);
    navigate("/dashboard");
  }

  return (
    <div className="split-layout">
      <div className="left-panel">
        <h1>🎓 Campus Connect</h1>
        <div className="tagline-box">
          <h2>Wide College Network</h2>
          <p>Favorite Space To Connect!</p>
        </div>
        <img
          src="https://img.freepik.com/premium-vector/graduation-students_1214-321.jpg"
          alt="Graduates"
          className="illustration"
        />
      </div>

      <div className="right-panel">
        <div className="form-box shadow-card">
          <div className="tabs">
            <Link to="/login" className="tab">Login</Link>
            <Link to="/register" className="tab active">Signup</Link>
          </div>

          <h2>Register</h2>
          <form onSubmit={handleRegister}>
            <label>Full Name</label>
            <input name="name" type="text" placeholder="Full Name" required />

            {/* ✅ Conditionally render Roll Number for students only */}
            {role === "student" && (
              <>
                <label>University Roll Number</label>
                <input name="roll" type="text" placeholder="University Roll Number" required />
              </>
            )}

            <label>Email</label>
            <input name="email" type="email" placeholder="Email" required />

            <label>Create Password</label>
            <input name="pass" type="password" placeholder="Create Password" required />

            <label>Confirm Password</label>
            <input name="cpass" type="password" placeholder="Confirm Password" required />

            <label>Role</label>
            <select name="role" required value={role} onChange={(e) => setRole(e.target.value)}>
              <option value="">-- Select Role --</option>
              <option value="student">Student</option>
              <option value="admin">Admin</option>
              <option value="hr">HR</option>
            </select>

            <button type="submit">Register</button>
          </form>

          <p className="signup-cta">
            Already have an account? <Link to="/login"><strong>Login</strong></Link>
          </p>
        </div>
      </div>
    </div>
  );
}
